// Package B: requires pkg-a (circular), captures what's available at that point.
'use strict';

var pkgA = require('pkg-a');

// At this point, pkg-a's early exports are visible but late exports are not yet set.
exports.name = 'pkg-b';
exports.sawPkgAName = pkgA.name;
exports.sawPkgAEarly = pkgA.early;
exports.sawPkgALate = pkgA.late; // should be undefined (not yet set when we required pkg-a)

// Keep a reference to pkg-a's exports object so we can check later
exports.pkgARef = pkgA;
